    )
    v2_auth_client.post(
        "/api/jobs/pin",
        json={"country": "uk", "company": co["name"], "url": second_job["url"], "pinned": True},
    )
    v2_auth_client.patch(
        "/api/jobs/pin",
        json={"country": "uk", "company": co["name"], "url": first_job["url"], "pinned": False},
